interface ProductFormPanelProps {
  product?: Product | null;
  isOpen: boolean;
  onClose: () => void;
  onSuccess: () => void;
}

export const ProductFormPanel = ({ product, isOpen, onClose, onSuccess }: ProductFormPanelProps) => {
  const [mounted, setMounted] = useState(false);
  const [loading, setLoading] = useState(false);
  const [fetching, setFetching] = useState(false);
  const [categories, setCategories] = useState<Category[]>([]);
  const [brands, setBrands] = useState<Brand[]>([]);
  
  const [formData, setFormData] = useState({
    name: "",
    slug: "",
    description: "",
    price: 0,
    comparePrice: 0,
    cost: 0,
    categoryId: "",
    brandId: "",
    status: "ACTIVE" as "ACTIVE" | "DRAFT" | "ARCHIVED",
    images: [] as { url: string; publicId: string; isMain: boolean }[],
    variants: [] as Partial<Variant>[],
  });

  useEffect(() => {
    setMounted(true);
  }, []);

  // Fetch meta-data (categories/brands) once when panel opens
  useEffect(() => {
    const fetchMetadata = async () => {
      try {
        const [catRes, brandRes] = await Promise.all([
          categoryApi.getAll(),
          brandApi.getAll()
        ]);
        if (catRes.data.success) setCategories(catRes.data.data);
        if (brandRes.data.success) setBrands(brandRes.data.data);
      } catch (err) {
        console.error("Failed to fetch meta data", err);
      }
    };
    if (isOpen) fetchMetadata();
  }, [isOpen]);

  useEffect(() => {
    if (product && isOpen) {
      setFetching(true);
      const fetchFullProduct = async () => {
        try {
          const res = await adminApi.getProductById(product.id);
          if (res.data.success) {
            const full = res.data.data;
            setFormData({
              name: full.name,
              slug: full.slug,
              description: full.description,
              price: full.price,
              comparePrice: (full as any).comparePrice || (full as any).comparePrice || 0,
              cost: (full as any).cost || 0,
              categoryId: full.categoryId,
              brandId: full.brandId,
              status: (full as any).status || "ACTIVE",
              images: full.images,
              variants: full.variants,
            });
          }
        } catch (err) {
          console.error("Failed to fetch full product", err);
          // Fallback
          setFormData({
            name: product.name,
            slug: product.slug,
            description: product.description,
            price: product.price,
            comparePrice: product.comparePrice || 0,
            cost: 0,
            categoryId: product.categoryId,
            brandId: product.brandId,
            status: (product as any).status || "ACTIVE",
            images: product.images,
            variants: product.variants,
          });
        } finally {
          setFetching(false);
        }
      };
      fetchFullProduct();
    } else if (!product && isOpen) {
      setFormData({
        name: "",
        slug: "",
        description: "",
        price: 0,
        comparePrice: 0,
        cost: 0,
        categoryId: "",
        brandId: "",
        status: "ACTIVE",
        images: [],
        variants: [],
      });
      setFetching(false);
    }
  }, [product, isOpen]);

  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = "hidden";
      const handleKeyDown = (e: KeyboardEvent) => {
        if (e.key === "Escape") onClose();
      };
      window.addEventListener("keydown", handleKeyDown);
      return () => {
        document.body.style.overflow = "unset";
        window.removeEventListener("keydown", handleKeyDown);
      };
    }
  }, [isOpen, onClose]);

  const handleNameChange = React.useCallback((name: string) => {
    const slug = name.toLowerCase().replace(/ /g, "-").replace(/[^\w-]+/g, "");
    setFormData(prev => ({ ...prev, name, slug }));
  }, []);

  const handleFieldChange = React.useCallback((field: string, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  }, []);

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const previewUrl = URL.createObjectURL(file);
    const tempId = `temp-${Date.now()}`;
    
    setFormData(prev => ({
      ...prev,
      images: [...prev.images, { url: previewUrl, publicId: tempId, isMain: prev.images.length === 0 }]
    }));

    setLoading(true);
    try {
      const res = await adminApi.uploadMedia(file);
      if (res.data.success) {
        setFormData(prev => ({
          ...prev,
          images: prev.images.map(img => 
            img.publicId === tempId ? { url: res.data.data.url, publicId: res.data.data.publicId, isMain: img.isMain } : img
          )
        }));
        toast.success("Imagery digitized successfully");
      }
    } catch (err) {
      setFormData(prev => ({ ...prev, images: prev.images.filter(img => img.publicId !== tempId) }));
      toast.error("Cloud ingestion failed");
    } finally {
      setLoading(false);
      URL.revokeObjectURL(previewUrl);
    }
  };

  const handleSetMain = React.useCallback((idx: number) => {
    setFormData(prev => ({
      ...prev,
      images: prev.images.map((im, i) => ({ ...im, isMain: i === idx }))
    }));
  }, []);

  const handleRemoveImage = React.useCallback((idx: number) => {
    setFormData(prev => ({
      ...prev,
      images: prev.images.filter((_, i) => i !== idx)
    }));
  }, []);

  const [formErrors, setFormErrors] = useState<Record<string, string>>({});
  
  const validateForm = () => {
    const errors: Record<string, string> = {};
    if (!formData.name.trim()) errors.name = "Title is required for the archive";
    if (!formData.categoryId) errors.categoryId = "Section classification required";
    if (!formData.brandId) errors.brandId = "Source attribution required";
    if (!formData.description.trim()) errors.description = "Editorial copy cannot be blank";
    if (formData.price <= 0) errors.price = "Valuation must be positive";
    
    // Ensure variants have at least basic data if present
    formData.variants.forEach((v, idx) => {
      if (v.size && !v.sku) {
        errors[`variant_${idx}_sku`] = "SKU required for defined sizing";
      }
    });

    setFormErrors(errors);
    return Object.keys(errors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    
    if (!validateForm()) {
      toast.error("Form incomplete. Review highlighted fields.");
      return;
    }

    setLoading(true);
    
    // Sanitize Payload
    const sanitizedPayload = {
      ...formData,
      variants: formData.variants.filter(v => v.size || v.color || v.sku), // Remove empty rows
      images: formData.images.filter(img => !img.publicId.startsWith('temp-')), // Ensure only synced images go
    };

    try {
      if (product) {
        await adminApi.updateProduct(product.id, sanitizedPayload);
        toast.success("Catalog entry updated");
      } else {
        await adminApi.createProduct(sanitizedPayload);
        toast.success("New piece added to collection");
      }
      onSuccess();
      onClose();
    } catch (err: any) {
      if (err.response?.status === 409) {
        toast.error("Conflict: This SKU or Slug already exists in the archive.");
      } else {
        toast.error("Sync failed. Check credentials and required fields.");
      }
    } finally {
      setLoading(false);
    }
  };

  const margin = useMemo(() => 
    formData.price > 0 ? (((formData.price - formData.cost) / formData.price) * 100).toFixed(0) : "0",
  [formData.price, formData.cost]);

  const categoryOptions = useMemo(() => categories.map(c => ({ label: c.name, value: c.id })), [categories]);
  const brandOptions = useMemo(() => brands.map(b => ({ label: b.name, value: b.id })), [brands]);

  if (!mounted) return null;

  return createPortal(
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-[100]">
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="fixed inset-0 bg-black/40 backdrop-blur-sm z-40"
          />
          <motion.div
            initial={{ x: "100%" }}
            animate={{ x: 0 }}
            exit={{ x: "100%" }}
            transition={{ type: "spring", damping: 30, stiffness: 250 }}
            style={{ willChange: "transform", z: 0 }}
            className="fixed inset-y-0 right-0 w-full sm:w-[420px] bg-white shadow-[0_10px_40px_rgba(0,0,0,0.2)] z-50 flex flex-col"
          >
            {/* Header */}
            <div className="px-8 py-8 border-b border-zinc-100 flex justify-between items-center sticky top-0 bg-white/80 backdrop-blur-xl z-20">
              <div className="space-y-1">
                <h3 className="text-2xl font-bold tracking-tight text-zinc-950">
                  {product ? "Refine Piece" : "New Archive"}
                </h3>
                <p className="text-[10px] text-zinc-400 font-bold uppercase tracking-[0.2em]">
                  {product ? `Collection Item REF: ${product.id.slice(-6).toUpperCase()}` : "Initiating catalog entry"}
                </p>
              </div>
              <CloseButton onClick={onClose} />
            </div>

            {/* Scroll Area */}
            <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto no-scrollbar px-8 py-10 space-y-16">
              {fetching ? (
                <FormSkeleton />
              ) : (
                <>
                  <IdentitySection 
                    {...formData}
                    categoryOptions={categoryOptions}
                    brandOptions={brandOptions}
                    onNameChange={handleNameChange}
                    onFieldChange={handleFieldChange}
                    errors={formErrors}
                  />

                  <PricingSection 
                    {...formData}
                    margin={margin}
                    onFieldChange={handleFieldChange}
                    errors={formErrors}
                  />

                  <MediaSection 
                    images={formData.images}
                    onUpload={handleImageUpload}
                    onSetMain={handleSetMain}
                    onRemove={handleRemoveImage}
                  />

                  <section>
                    <ProductVariantsTable 
                      variants={formData.variants} 
                      onChange={(variants) => handleFieldChange("variants", variants)} 
                      errors={formErrors}
                    />
                  </section>

                  <section className="space-y-8">
                    <div className="flex items-center gap-4">
                      <div className="h-[1px] flex-1 bg-zinc-100" />
                      <h4 className="text-[10px] font-bold uppercase tracking-[0.2em] text-zinc-400">Search Presence</h4>
                      <div className="h-[1px] flex-1 bg-zinc-100" />
                    </div>
                    
                    <div className="p-8 bg-zinc-50/50 rounded-xl space-y-3 border border-zinc-100 shadow-inner">
                      <p className="text-[#1a0dab] text-xl font-medium tracking-tight truncate hover:underline cursor-pointer">
                        {formData.name || "Product Archive Piece"} | Editorial curator
                      </p>
                      <div className="flex items-center gap-1.5 text-[#006621] text-xs font-medium">
                        <span>thecurator.com</span>
                        <ArrowRight size={10} className="text-zinc-400" />
                        <span className="truncate">{formData.slug || "item-pathway"}</span>
                      </div>
                      <p className="text-zinc-500 text-[13px] leading-relaxed line-clamp-2 italic font-serif">
                        {formData.description || "Refining the intersection of modern utility and timeless editorial aesthetics... "}
                      </p>
                    </div>
                  </section>
                </>
              )}
            </form>

            {/* Footer */}
            <div className="px-8 py-8 border-t border-zinc-100 bg-white sticky bottom-0 flex gap-4 shadow-[0_-20px_60px_rgba(0,0,0,0.02)] z-20">
              <Button
                variant="outline"
                className="flex-1 font-black uppercase tracking-[0.2em] text-[10px] py-6 rounded-sm"
                onClick={onClose}
                disabled={fetching}
              >
                Discard
              </Button>
              <Button
                type="submit"
                variant="primary"
                className="flex-1 font-black uppercase tracking-[0.2em] text-[10px] py-6 rounded-sm shadow-2xl shadow-black/10 transition-all hover:-translate-y-0.5"
                onClick={handleSubmit}
                isLoading={loading}
                disabled={fetching}
              >
                {product ? "Sync Archive" : "Manifest Collection"}
              </Button>
            </div>
          </motion.div>
        </div>
      )}
    </AnimatePresence>,
    document.body
  );
};

"use client";

import React from "react";
import { Variant } from "@/types";
import { Button } from "../ui/Button";
import { Input } from "../ui/Input";
import { Trash2, Plus } from "lucide-react";
import ColorPicker from "./ColorPicker";

interface ProductVariantsTableProps {
  variants: Partial<Variant>[];
  onChange: (variants: Partial<Variant>[]) => void;
  errors?: Record<string, string>;
}

const VariantRow = ({ variant, index, onUpdate, onRemove, errors }: any) => {
  return (
    <tr className="group hover:bg-zinc-50 transition">
      <td className="px-4 py-3">
        <input
          value={variant.size || ""}
          onChange={(e) => onUpdate(index, "size", e.target.value)}
          placeholder="S, M, L"
          className="w-full py-2 bg-transparent border-none focus:outline-none focus:ring-0 text-sm text-zinc-900"
        />
      </td>
      <td className="px-4 py-3">
        <Input
          value={variant.color || ""}
          onChange={(e) => onUpdate(index, "color", e.target.value)}
          placeholder="Black"
          className="w-full py-2 bg-transparent border-transparent hover:border-zinc-200 focus:bg-white focus:border-zinc-300 transition-all text-sm text-zinc-900"
        />
      </td>
      <td className="px-4 py-3">
        <ColorPicker
          value={variant.colorHex || "#000000"}
          onChange={(val) => onUpdate(index, "colorHex", val)}
        />
      </td>
      <td className="px-4 py-3">
        <Input
          type="number"
          value={variant.stock ?? 0}
          onChange={(e) => onUpdate(index, "stock", parseInt(e.target.value) || 0)}
          className="w-24 py-2 bg-transparent border-transparent hover:border-zinc-200 focus:bg-white focus:border-zinc-300 transition-all text-center font-bold text-sm text-zinc-900"
        />
      </td>
      <td className="px-4 py-3">
        <Input
          value={variant.sku || ""}
          onChange={(e) => onUpdate(index, "sku", e.target.value)}
          placeholder="SKU-001"
          className="w-full py-2 font-mono bg-transparent border-transparent hover:border-zinc-200 focus:bg-white focus:border-zinc-300 transition-all text-sm text-zinc-900"
          error={errors?.[`variant_${index}_sku`]}
        />
      </td>
      <td className="px-4 py-3 text-right">
        <Button
          type="button"
          variant="icon"
          size="none"
          onClick={() => onRemove(index)}
          className="text-zinc-300 hover:text-red-500 hover:bg-red-50 p-2 rounded-full opacity-0 group-hover:opacity-100 transition-all active:scale-95"
          icon={<Trash2 size={16} />}
        />
      </td>
    </tr>
  );
};

export const ProductVariantsTable = ({ variants, onChange, errors }: ProductVariantsTableProps) => {
  const addRow = () => {
    onChange([
      ...variants,
      { size: "", color: "", colorHex: "#000000", stock: 0, sku: "" },
    ]);
  };

  const removeRow = (index: number) => {
    onChange(variants.filter((_, i) => i !== index));
  };

  const updateRow = (index: number, field: keyof Variant, value: any) => {
    const updated = [...variants];
    updated[index] = { ...updated[index], [field]: value };
    onChange(updated);
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h4 className="text-[10px] font-bold uppercase tracking-widest text-zinc-400">Variant Matrix</h4>
        <Button 
          variant="outline" 
          size="sm" 
          type="button"
          onClick={addRow}
          className="text-[10px] font-bold uppercase tracking-widest rounded-lg"
          icon={<Plus size={14} />}
        >
          Add Variant
        </Button>
      </div>

      <div className="overflow-x-auto scrollbar-thin scrollbar-thumb-zinc-300 rounded-xl border border-zinc-100 bg-white shadow-sm">
        <table className="w-full text-left align-middle border-collapse min-w-[600px]">
          <thead className="bg-zinc-50/50 text-xs uppercase tracking-wide text-zinc-500 border-b border-zinc-100">
            <tr>
              <th className="px-4 py-3 font-medium">Size</th>
              <th className="px-4 py-3 font-medium">Color</th>
              <th className="px-4 py-3 font-medium">Hex Code</th>
              <th className="px-4 py-3 font-medium">Stock</th>
              <th className="px-4 py-3 font-medium">SKU Reference</th>
              <th className="px-4 py-3 text-right"></th>
            </tr>
          </thead>
          <tbody className="divide-y divide-zinc-50">
            {variants.map((variant, index) => (
              <VariantRow 
                key={variant.id || `new-${index}`}
                variant={variant}
                index={index}
                onUpdate={updateRow}
                onRemove={removeRow}
                errors={errors}
              />
            ))}
            {variants.length === 0 && (
              <tr>
                <td colSpan={6} className="px-6 py-12 text-center text-xs text-zinc-400 italic">
                  No variants defined. Utilize variants to manage size and color complexity.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

