import React, { useEffect, useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { cn } from "@/lib/utils";
import { categoryApi, brandApi, productApi } from "@/lib/api";
import { Category } from "@/types";
import { Button } from "../ui/Button";

export interface FilterState {
  category: string[];
  brand: string[];
  size: string[];
  color: string[];
  minPrice: number;
  maxPrice: number;
  sort: string;
}

export type FilterAction =
  | { type: "toggle_category"; payload: string }
  | { type: "toggle_brand"; payload: string }
  | { type: "toggle_color"; payload: string }
  | { type: "set_max_price"; payload: number }
  | { type: "set_sort"; payload: string }
  | { type: "reset" }
  | { type: "sync_from_url"; payload: Partial<FilterState> };


interface FilterSidebarProps {
  state: FilterState;
  dispatch: React.Dispatch<FilterAction>;
  isOpen?: boolean;
  onClose?: () => void;
  isMobile?: boolean;
}

export const FilterSidebar = ({ state, dispatch, isOpen, onClose, isMobile }: FilterSidebarProps) => {
  const [categories, setCategories] = useState<string[]>([]);
  const [brands, setBrands] = useState<{ id: string; name: string; slug: string }[]>([]);
  const [colors, setColors] = useState<{ name: string; class: string; hex: string }[]>([]);

  useEffect(() => {
    const fetchFilterData = async () => {
      try {
        // Fetch Categories
        const catRes = await categoryApi.getAll();
        if (catRes.data.success) {
          setCategories(catRes.data.data.map((c: Category) => c.name));
        }

        // Fetch Brands
        const brandRes = await brandApi.getAll();
        if (brandRes.data.success) {
          setBrands(brandRes.data.data);
        }

        // Fetch Product Filters (Colors)
        const filterRes = await productApi.getFilters();
        if (filterRes.data.success) {
          const rawColors = filterRes.data.data.colors;
          // Aggressively deduplicate by hex only — visually identical colors should appear once
          const seenHex = new Set<string>();
          const uniqueColors = rawColors.filter((color: any) => {
            const hex = color.hex.toLowerCase().trim();
            if (seenHex.has(hex)) return false;
            seenHex.add(hex);
            return true;
          });

          setColors(uniqueColors.map((c: { name: string; hex: string }) => ({
            name: c.name,
            class: "",
            hex: c.hex
          })));
        }
      } catch (error) {
        console.error("Failed to fetch filter data:", error);
      }
    };
    fetchFilterData();
  }, []);

  const content = (
    <div className="space-y-8 flex flex-col h-full pb-6">
      <div className="space-y-1">
        <h2 className="font-headline text-sm uppercase tracking-widest text-on-surface-stone-900 font-bold text-stone-50">
          FILTER
        </h2>
        <p className="text-[10px] uppercase tracking-widest text-stone-400">
          Refine Selection
        </p>
      </div>

      <div className="space-y-8 flex-1">
        {/* Categories */}
        <section>
          <h3 className="text-[11px] font-bold uppercase tracking-widest mb-4">Categories</h3>
          <div className="flex flex-col gap-3">
            {categories.map((cat) => (
              <label key={cat} className="flex items-center gap-3 cursor-pointer group">
                <input 
                  type="checkbox" 
                  checked={state.category.includes(cat)}
                  onChange={() => dispatch({ type: "toggle_category", payload: cat })}
                  className="w-4 h-4 border-outline-variant text-primary focus:ring-primary rounded-sm bg-transparent"
                />
                <span className={cn(
                  "text-xs uppercase tracking-wider transition-colors",
                  state.category.includes(cat) ? "text-stone-900 dark:text-stone-50" : "text-stone-400 group-hover:text-stone-900"
                )}>
                  {cat}
                </span>
              </label>
            ))}
          </div>
        </section>

        {/* Brands */}
        {brands.length > 0 && (
          <section>
            <h3 className="text-[11px] font-bold uppercase tracking-widest mb-4">Brands</h3>
            <div className="flex flex-col gap-3">
              {brands.map((brand) => (
                <label key={brand.id} className="flex items-center gap-3 cursor-pointer group">
                  <input 
                    type="checkbox" 
                    checked={state.brand.includes(brand.slug)}
                    onChange={() => dispatch({ type: "toggle_brand", payload: brand.slug })}
                    className="w-4 h-4 border-outline-variant text-primary focus:ring-primary rounded-sm bg-transparent"
                  />
                  <span className={cn(
                    "text-xs uppercase tracking-wider transition-colors",
                    state.brand.includes(brand.slug) ? "text-stone-900 dark:text-stone-50" : "text-stone-400 group-hover:text-stone-900"
                  )}>
                    {brand.name}
                  </span>
                </label>
              ))}
            </div>
          </section>
        )}

        {/* Price Range */}
        <section>
          <h3 className="text-[11px] font-bold uppercase tracking-widest mb-4">Price Range</h3>
          <input 
            type="range"
            min="0"
            max="2000"
            value={state.maxPrice}
            onChange={(e) => dispatch({ type: "set_max_price", payload: parseInt(e.target.value) })}
            className="w-full h-1 bg-surface-container-highest rounded-full appearance-none cursor-pointer accent-primary" 
          />
          <div className="flex justify-between mt-2 text-[10px] text-stone-500">
            <span>$0</span>
            <span>${state.maxPrice}+</span>
          </div>
        </section>

        {/* Colors */}
        <section className="max-w-full pb-4">
          <h3 className="text-[11px] font-bold uppercase tracking-widest mb-4">Colors</h3>
          <div className="flex flex-wrap gap-3 p-1">
            {colors.map((color) => (
              <Button 
                key={color.name}
                variant="none"
                size="none"
                onClick={() => dispatch({ type: "toggle_color", payload: color.name })}
                className={cn(
                  "w-6 h-6 rounded-full ring-1 transition-all hover:scale-110 cursor-pointer",
                  state.color.includes(color.name) ? "ring-offset-2 ring-primary" : "ring-stone-200"
                )}
                style={{ backgroundColor: color.hex }}
                title={color.name}
                aria-label={`Filter by color ${color.name}`}
              />
            ))}
          </div>
        </section>
      </div>


    </div>
  );

  if (isMobile) {
    return (
      <AnimatePresence>
        {isOpen && (
          <>
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              onClick={onClose}
              className="fixed inset-0 bg-black/40 backdrop-blur-sm z-60"
            />
            <motion.div
              initial={{ y: "100%" }}
              animate={{ y: 0 }}
              exit={{ y: "100%" }}
              transition={{ type: "spring", damping: 25, stiffness: 200 }}
              className="fixed inset-x-0 bottom-0 bg-surface z-70 rounded-t-3xl p-8 max-h-[85vh] overflow-y-auto"
            >
              {content}
            </motion.div>
          </>
        )}
      </AnimatePresence>
    );
  }

  return (
    <aside className="sticky top-20 h-[calc(100vh-5rem)] w-64 shrink-0 flex-col p-8 gap-6 bg-stone-50 dark:bg-stone-900 border-none hidden lg:flex overflow-y-auto premium-scrollbar">
      {content}
    </aside>
  );
};

'use client'

import React, { useEffect, useState, useRef } from "react"
import Image from 'next/image'
import Link from 'next/link'
import { Button } from "@/components/ui/Button"

interface Props {
  excludeId: string
}

export const HorizontalScroll = ({ excludeId }: Props) => {
  const [products, setProducts] = useState<any[]>([])
  const [loading, setLoading] = useState(true)
  const scrollRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    let isMounted = true
    const fetchFeatured = async () => {
      try {
        const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/products?limit=8`)
        const data = await res.json()
        if (isMounted) {
          const filtered = data.data
            ?.filter((p: any) => p.id !== excludeId)
            ?.slice(0, 8) || []
          setProducts(filtered)
        }
      } catch (err) {
        if (isMounted) setProducts([])
      } finally {
        if (isMounted) setLoading(false)
      }
    }
    fetchFeatured()
    return () => { isMounted = false }
  }, [excludeId])

  const scroll = (direction: "left" | "right") => {
    if (scrollRef.current) {
      const scrollAmount = 400
      scrollRef.current.scrollBy({
        left: direction === "left" ? -scrollAmount : scrollAmount,
        behavior: "smooth",
      })
    }
  }

  if (loading) {
    return (
      <section className="bg-surface-container-low py-24 sm:py-32">
        <div className="max-w-[1440px] w-full mx-auto px-12">
          <div className="flex justify-between items-end mb-12">
            <h2 className="text-4xl font-medium tracking-tight">Complete the Look</h2>
          </div>
          <div className="flex gap-8 overflow-x-auto pb-12">
            {[...Array(4)].map((_, i) => (
              <div key={i} className="min-w-[320px]">
                <div className="aspect-3/4 bg-surface-container mb-4 overflow-hidden animate-pulse rounded" />
                <div className="h-4 w-2/3 bg-surface-container rounded mb-2 animate-pulse" />
                <div className="h-4 w-1/4 bg-surface-container rounded animate-pulse" />
              </div>
            ))}
          </div>
          <div className="w-[98%] h-[2px] bg-black/90 dark:bg-white/90 mt-2 mb-8"></div>
        </div>
      </section>
    )
  }

  if (products.length === 0) return null

  return (
    <section className="bg-surface-container-low py-24 sm:py-32">
      <div className="max-w-[1440px] w-full mx-auto px-12">
        <div className="flex justify-between items-end mb-12">
          <h2 className="text-4xl font-medium tracking-tight">Complete the Look</h2>
          <div className="flex gap-4">
            <Button 
              variant="outline"
              size="none"
              onClick={() => scroll("left")}
              className="w-12 h-12 rounded-full flex items-center justify-center group"
              icon={
                <span className="material-symbols-outlined transition-transform group-hover:-translate-x-0.5">chevron_left</span>
              }
            />
            <Button 
              variant="outline"
              size="none"
              onClick={() => scroll("right")}
              className="w-12 h-12 rounded-full flex items-center justify-center group"
              icon={
                <span className="material-symbols-outlined transition-transform group-hover:translate-x-0.5">chevron_right</span>
              }
            />
          </div>
        </div>

        <div 
          ref={scrollRef}
          className="flex gap-8 overflow-x-auto custom-scrollbar pb-12 snap-x"
          style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
        >
          {products.map((product: any, idx: number) => (
            <Link 
              key={product.id}
              href={`/products/${product.id}`}
              className="min-w-[320px] snap-start group animate-in fade-in slide-in-from-right-8 duration-700 fill-mode-both"
              style={{ animationDelay: `${idx * 100}ms` }}
            >
              <div className="aspect-3/4 bg-white overflow-hidden mb-4 relative">
                <Image 
                  src={product.images?.[0]?.url || '/placeholder.jpg'}
                  alt={product.name}
                  fill
                  className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700"
                />
              </div>
              <h4 className="font-medium truncate">{product.name}</h4>
              <p className="text-on-surface-variant text-sm mt-1">${product.price.toFixed(2)}</p>
            </Link>
          ))}
        </div>
          <div className="w-[98%] h-[2px] bg-black/90 dark:bg-white/90 mt-2 mb-8"></div>
      </div>
    </section>
  )
}

import React, { useState, useRef } from "react";
import Link from "next/link";
import { motion, AnimatePresence } from "framer-motion";
import { Star, Heart, Plus, Check } from "lucide-react";
import { Product } from "@/types";
import { toast } from "sonner";
import { formatCurrency, cn } from "@/lib/utils";
import { useCartStore } from "@/store/cartStore";
import { useAuthStore } from "@/store/authStore";
import { useWishlistStore } from "@/store/wishlistStore";
import { useRouter } from "next/navigation";
import { Button } from "../ui/Button";
import { flyToCart } from "@/lib/animations";
import { RatingDisplay } from "../ui/RatingDisplay";


interface ProductCardProps {
  product: Product;
  className?: string;
  delay?: number;
  variant?: "default" | "editorial";
  isListView?: boolean;
}



export const ProductCard = ({ product, className, delay = 0, variant = "default", isListView = false }: ProductCardProps) => {
  const { addItem, toggleDrawer } = useCartStore();
  const { isAuthenticated } = useAuthStore();
  const { items: wishlistItems, addItem: addToWishlist, removeItem: removeFromWishlist, isInWishlist } = useWishlistStore();
  const router = useRouter();
  const [status, setStatus] = useState<"idle" | "loading" | "success">("idle");
  const isAnimating = useRef(false);
  const imageRef = useRef<HTMLImageElement>(null);

  const isFavorite = isInWishlist(product.id);

  const handleAddToCart = async (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();

    if (isAnimating.current) return;
    isAnimating.current = true;

    const productVariant = product.variants?.[0];
    if (!productVariant) return;

    const start = Date.now();
    setStatus("loading");
    flyToCart(imageRef);

    await addItem({
      id: '', // Server handles IDs
      cartItemId: '',
      productId: product.id,
      variantId: productVariant.id,
      name: product.name,
      image: product.images.find(img => img.isMain)?.url || product.images[0]?.url || "",
      price: product.price,
      size: productVariant.size,
      color: productVariant.color,
      quantity: 1,
      stock: productVariant.stock || 10,
    });

    // Ensure minimum 600ms loading state
    const elapsed = Date.now() - start;
    if (elapsed < 600) {
      await new Promise(r => setTimeout(r, 600 - elapsed));
    }


    setStatus("success");
    flyToCart(imageRef);

    setTimeout(() => {
      toggleDrawer(true);
      setStatus("idle");
      isAnimating.current = false;
    }, 800);
  };

  const toggleFavorite = async (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (!isAuthenticated) { 
      toast.info("Please sign in to save items to your wishlist"); 
      return; 
    }

    try {
      if (isFavorite) {
        await removeFromWishlist(product.id);
      } else {
        await addToWishlist(product.id);
      }
    } catch (err) {
      console.error('Wishlist error:', err);
    }
  };

  // Removed renderStars in favor of RatingDisplay

  if (isListView) {
    return (
      <motion.article
        initial={{ opacity: 0, x: -20 }}
        animate={{ opacity: 1, x: 0 }}
        transition={{ duration: 0.5, ease: [0.16, 1, 0.3, 1], delay }}
        className={cn("group flex flex-col sm:flex-row gap-8 items-center bg-surface p-4 sm:p-0 border-b border-outline-variant/10 pb-12 sm:border-none sm:pb-0", className)}
      >
        <Link href={`/products/${product.id}`} className="shrink-0 w-full sm:w-64 aspect-3/4 sm:aspect-square relative overflow-hidden bg-surface-container-low group-hover:-translate-y-1 transition-transform duration-500">
          {product.images[0] && (
            <img
              ref={imageRef}
              src={product.images.find(img => img.isMain)?.url || product.images[0].url}
              alt={product.name}
              className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105"
            />
          )}
          <Button
            variant="icon"
            size="icon"
            onClick={toggleFavorite}
            isActive={isFavorite}
            className={cn(
              "absolute top-4 right-4 z-10 backdrop-blur-md rounded-full transition-all duration-300 group/fav",
              isFavorite ? "bg-black text-white!" : "bg-black/40 text-white! hover:bg-black"
            )}
            aria-label={isFavorite ? "Remove from favorites" : "Add to favorites"}
          >
            <Heart 
              size={18} 
              className={cn(
                "transition-all duration-300",
                isFavorite ? "fill-white!" : "group-hover/fav:fill-white!"
              )} 
            />
          </Button>
        </Link>

        <div className="flex-1 space-y-4 py-2">
          <div>
            <p className="text-[10px] uppercase tracking-[0.2em] text-on-surface-variant mb-2 font-bold">
              {product.brand?.name || "THE CURATOR"}
            </p>
            <h3 className="text-xl sm:text-2xl font-medium tracking-tight group-hover:text-primary transition-colors">
              <Link href={`/products/${product.id}`}>{product.name}</Link>
            </h3>
          </div>

          <p className="text-sm text-on-surface-variant line-clamp-2 max-w-xl leading-relaxed">
            {product.description || "Experimental design meets sustainable craftsmanship in this signature piece from our latest collection."}
          </p>

          <div className="flex items-center gap-6">
            <span className="text-xl font-bold tracking-tighter">{formatCurrency(product.price)}</span>
            <div className="h-4 w-px bg-outline-variant" />
            <RatingDisplay rating={product.avgRating} count={product.reviewCount} />
          </div>

          <div className="flex flex-wrap gap-4 pt-4">
            {product.variants?.[0] && (
              <Button 
                variant={status === "success" ? "success" : "primary"}
                onClick={handleAddToCart}
                disabled={status !== "idle"}
                className="px-8 py-3 text-[10px] font-bold uppercase tracking-[0.2em] transition-all active:scale-95 shadow-lg cursor-pointer min-w-[160px]"
              >
                <AnimatePresence mode="wait">
                  {status === "idle" && (
                    <motion.span
                      key="idle"
                      initial={{ opacity: 0, y: 5 }}
                      animate={{ opacity: 1, y: 0 }}
                      exit={{ opacity: 0, y: -5 }}
                      transition={{ duration: 0.2 }}
                    >
                      Add to Collection
                    </motion.span>
                  )}
                  {status === "loading" && (
                    <motion.span
                      key="loading"
                      initial={{ opacity: 0 }}
                      animate={{ opacity: 1 }}
                      exit={{ opacity: 0 }}
                      className="flex items-center justify-center font-bold"
                    >
                      <div className="h-4 w-4 animate-spin rounded-full border-2 border-current border-t-transparent" />
                    </motion.span>
                  )}
                  {status === "success" && (
                    <motion.span
                      key="success"
                      initial={{ opacity: 0, y: 5 }}
                      animate={{ opacity: 1, y: 0 }}
                      exit={{ opacity: 0, y: -5 }}
                      className="flex items-center gap-2"
                    >
                      <Check size={16} /> Added
                    </motion.span>
                  )}
                </AnimatePresence>
              </Button>
            )}
            <Link 
              href={`/products/${product.id}`}
              className="px-8 py-3 border border-outline text-[10px] font-bold uppercase tracking-[0.2em] hover:bg-surface-container transition-all active:scale-95 flex items-center justify-center cursor-pointer"
            >
              View Details
            </Link>
          </div>
        </div>
      </motion.article>
    );
  }

  if (variant === "editorial") {
    return (
      <article
        className={cn("group cinematic-reveal", className)}
        style={{ animationDelay: `${delay}s` }}
      >
        <Link href={`/products/${product.id}`} className="block">
          <div className="relative overflow-hidden aspect-3/4 bg-surface-container-low mb-6">
            {product.images[0] && (
              <img
                ref={imageRef}
                src={product.images.find(img => img.isMain)?.url || product.images[0].url}
                alt={product.name}
                className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105"
              />
            )}

            <Button
              variant="icon"
              size="icon"
              onClick={toggleFavorite}
              isActive={isFavorite}
              className={cn(
                "absolute top-4 right-4 z-10 backdrop-blur-md rounded-full transition-all duration-300 group/fav",
                isFavorite ? "bg-black text-white!" : "bg-black/40 text-white! hover:bg-black"
              )}
              aria-label={isFavorite ? "Remove from favorites" : "Add to favorites"}
              icon={
                <Heart 
                  size={20} 
                  className={cn(
                    "transition-all duration-300",
                    isFavorite ? "fill-white!" : "group-hover/fav:fill-white!"
                  )}
                  strokeWidth={1.5}
                />
              }
            />

            {product.variants?.[0] && (
              <Button
                variant={status === "success" ? "success" : "primary"}
                onClick={handleAddToCart}
                disabled={status !== "idle"}
                className="absolute bottom-0 left-0 w-full py-6 translate-y-full group-hover:translate-y-0 duration-500 ease-[cubic-bezier(0.16,1,0.3,1)] z-10"
                size="none"
              >
                <AnimatePresence mode="wait">
                  {status === "idle" && (
                    <motion.span
                      key="idle"
                      initial={{ opacity: 0, y: 5 }}
                      animate={{ opacity: 1, y: 0 }}
                      exit={{ opacity: 0, y: -5 }}
                      transition={{ duration: 0.2 }}
                    >
                      Quick Add
                    </motion.span>
                  )}
                  {status === "loading" && (
                    <motion.span
                      key="loading"
                      initial={{ opacity: 0 }}
                      animate={{ opacity: 1 }}
                      exit={{ opacity: 0 }}
                      className="flex items-center justify-center"
                    >
                      <div className="h-4 w-4 animate-spin rounded-full border-2 border-current border-t-transparent" />
                    </motion.span>
                  )}
                  {status === "success" && (
                    <motion.span
                      key="success"
                      initial={{ opacity: 0, y: 5 }}
                      animate={{ opacity: 1, y: 0 }}
                      exit={{ opacity: 0, y: -5 }}
                      className="flex items-center gap-2"
                    >
                      <Check size={18} /> Added
                    </motion.span>
                  )}
                </AnimatePresence>
              </Button>
            )}
          </div>

          <div className="space-y-1 mt-6">
            <p className="text-[10px] uppercase tracking-widest text-on-surface-variant">
              {product.brand?.name || "THE CURATOR"}
            </p>
            <div className="flex justify-between items-start">
              <h3 className="text-sm font-medium tracking-tight">{product.name}</h3>
              <span className="text-sm font-medium">{formatCurrency(product.price)}</span>
            </div>
            <RatingDisplay rating={product.avgRating} count={product.reviewCount} />
          </div>
        </Link>
      </article>
    );
  }

  // Default Variant
  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true, margin: "-10% 0px" }}
      transition={{ duration: 0.6, ease: [0.16, 1, 0.3, 1] as const, delay }}
      className={cn("group", className)}
    >
      <Link href={`/products/${product.id}`} className="block">
        <div className="relative aspect-4/5 bg-surface-container-low overflow-hidden mb-6 cinematic-ease duration-500 group-hover:-translate-y-2">
          {product.images[0] && (
            <img
              ref={imageRef}
              src={product.images.find(img => img.isMain)?.url || product.images[0].url}
              alt={product.name}
              className="w-full h-full object-cover cinematic-ease duration-[0.8s] group-hover:scale-110"
            />
          )}

          {product.variants?.[0] && (
            <Button
              variant={status === "success" ? "success" : "primary"}
              size="icon"
              onClick={handleAddToCart}
              disabled={status !== "idle"}
              className="absolute bottom-6 right-6 w-12 h-12 bg-primary text-on-primary rounded-full flex items-center justify-center opacity-0 translate-y-4 group-hover:opacity-100 group-hover:translate-y-0 transition-all duration-500 delay-100 shadow-xl cursor-pointer"
              aria-label="Add to cart"
            >
              <AnimatePresence mode="wait">
                {status === "idle" && (
                  <motion.span
                    key="idle"
                    initial={{ opacity: 0, scale: 0.5 }}
                    animate={{ opacity: 1, scale: 1 }}
                    exit={{ opacity: 0, scale: 0.5 }}
                  >
                    <Plus size={24} strokeWidth={1.5} />
                  </motion.span>
                )}
                {status === "loading" && (
                  <motion.span
                    key="loading"
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 1 }}
                    exit={{ opacity: 0 }}
                  >
                    <div className="h-5 w-5 animate-spin rounded-full border-2 border-current border-t-transparent" />
                  </motion.span>
                )}
                {status === "success" && (
                  <motion.span
                    key="success"
                    initial={{ opacity: 0, scale: 0.5 }}
                    animate={{ opacity: 1, scale: 1 }}
                    exit={{ opacity: 0, scale: 0.5 }}
                  >
                    <Check size={24} />
                  </motion.span>
                )}
              </AnimatePresence>
            </Button>
          )}
        </div>

        <div className="flex justify-between items-start">
          <div>
            <h4 className="text-lg font-medium text-on-surface">{product.name}</h4>
            <p className="text-on-surface-variant text-sm mt-1">
              {product.variants?.[0]?.color || "Default"}
            </p>
          </div>
          <span className="text-lg font-bold tracking-tighter text-on-surface">
            {formatCurrency(product.price)}
          </span>
        </div>
      </Link>
    </motion.div>
  );
};

"use client";

import React, { useState, useRef } from "react";
import { Product } from "@/types";
import { formatCurrency, cn } from "@/lib/utils";
import { useCartStore } from "@/store/cartStore";
import { motion, AnimatePresence } from "framer-motion";
import { productApi } from "@/lib/api";
import { useAuthStore } from "@/store/authStore";
import { useWishlistStore } from "@/store/wishlistStore";
import { useRouter } from "next/navigation";
import { Button } from "../ui/Button";
import { flyToCart } from "@/lib/animations";
import { toast } from "sonner";
import { RatingDisplay } from "../ui/RatingDisplay";

interface ProductInfoProps {
  product: Product;
}



type ButtonState = "idle" | "loading" | "success";

export const ProductInfo = ({ product }: ProductInfoProps) => {
  const { addItem, toggleDrawer } = useCartStore();

  const [selectedColor, setSelectedColor] = useState<string>(
    product.variants?.[0]?.color || ""
  );
  const [selectedSize, setSelectedSize] = useState<string>(
    product.variants?.[0]?.size || ""
  );
  const [quantity, setQuantity] = useState(1);
  const [buttonState, setButtonState] = useState<ButtonState>("idle");
  const isAnimating = useRef(false);
  const { isAuthenticated } = useAuthStore();
  const { addItem: addToWishlist, removeItem: removeFromWishlist, isInWishlist } = useWishlistStore();
  const router = useRouter();

  const isFavorite = isInWishlist(product.id);

  const availableSizes = product.variants
    .filter((v) => v.color === selectedColor)
    .map((v) => v.size);

  const currentVariant = product.variants.find(
    (v) => v.size === selectedSize && v.color === selectedColor
  );

  const colors = Array.from(new Set(product.variants.map((v) => v.color)));

  const handleAddToCart = async (e?: React.MouseEvent) => {
    if (e) {
      e.preventDefault();
      e.stopPropagation();
    }

    if (!currentVariant || isAnimating.current) return;
    isAnimating.current = true;

    const start = Date.now();
    setButtonState("loading");

    await addItem({
      id: '', // Server handles IDs
      cartItemId: '',
      productId: product.id,
      variantId: currentVariant.id,
      name: product.name,
      image: product.images.find((img) => img.isMain)?.url || product.images[0]?.url || "",
      price: product.price,
      size: currentVariant.size,
      color: currentVariant.color,
      quantity,
      stock: currentVariant.stock,
    });

    // Ensure minimum 600ms loading state
    const elapsed = Date.now() - start;
    if (elapsed < 600) {
      await new Promise(r => setTimeout(r, 600 - elapsed));
    }

    setButtonState("success");

    // Trigger fly animation immediately
    const mainImg = document.getElementById('pdp-main-image');
    flyToCart(mainImg);

    setTimeout(() => {
      toggleDrawer(true);
      setButtonState("idle");
      isAnimating.current = false;
    }, 800);
  };

  const toggleWishlist = async () => {
    if (!isAuthenticated) {
      toast.info("Please sign in to save items to your wishlist");
      return;
    }

    try {
      if (isFavorite) {
        await removeFromWishlist(product.id);
      } else {
        await addToWishlist(product.id);
      }
    } catch (err) {
      console.error("Wishlist error:", err);
    }
  };

  return (
    <div className="sticky top-32 space-y-8 animate-in fade-in slide-in-from-right-8 duration-700">
      <div>
        <p className="text-xs tracking-[0.2em] uppercase text-on-surface-variant mb-2">
          {product.brand?.name || "ESSENTIALS COLLECTION"}
        </p>
        <h1 className="text-[32px] font-medium leading-tight text-on-surface">
          {product.name}
        </h1>
        <RatingDisplay rating={product.avgRating} count={product.reviewCount} size={14} className="mt-3" />
      </div>

      <div className="text-[28px] font-bold text-on-surface">
        {formatCurrency(product.price)}
      </div>

      <div className="space-y-4">
        <p className="text-xs font-label tracking-widest uppercase">
          Color / <span className="text-primary">{selectedColor}</span>
        </p>
        <div className="flex gap-3">
          {product.variants
            .filter((v, i, arr) => arr.findIndex(x => x.color === v.color) === i) // unique colors
            .map((variant) => (
              <Button
                variant="none"
                key={variant.color}
                onClick={() => setSelectedColor(variant.color)}
                style={{ backgroundColor: variant.colorHex || '#ccc' }}
                className={cn(
                  "w-7 h-7 rounded-full border-2 transition-all p-0",
                  selectedColor === variant.color 
                    ? 'border-zinc-950 scale-110' 
                    : 'border-transparent hover:border-zinc-200'
                )}
                title={variant.color}
                aria-label={`Select color ${variant.color}`}
              />
            ))}
        </div>
      </div>

      <div className="space-y-4">
        <div className="flex justify-between items-center">
          <p className="text-xs font-label tracking-widest uppercase">Size</p>
          <a 
            href="/size-guide"
            target="_blank"
            rel="noopener noreferrer"
            className="text-xs underline text-on-surface-variant hover:text-primary transition-colors"
          >
            Size Guide
          </a>
        </div>
        <div className="grid grid-cols-4 gap-2">
          {availableSizes.map((size) => (
            <Button
              key={size}
              onClick={() => setSelectedSize(size)}
              variant={selectedSize === size ? "primary" : "outline"}
              size="none"
              className={cn(
                "py-3 text-sm border transition-all duration-200",
                selectedSize === size
                  ? "border-primary bg-primary text-white"
                  : "border-outline-variant hover:border-primary text-on-surface"
              )}
            >
              {size}
            </Button>
          ))}
        </div>
      </div>

      <div className="flex gap-4">
        <div className="flex items-center border border-outline-variant bg-white">
          <Button 
            variant="ghost"
            size="none"
            onClick={() => setQuantity(Math.max(1, quantity - 1))}
            className="p-3 hover:text-primary transition-colors"
            aria-label="Decrease quantity"
          >
            <span className="material-symbols-outlined text-lg">remove</span>
          </Button>
          <span className="mx-4 text-sm tabular-nums min-w-1.5rem text-center">{quantity}</span>
          <Button 
            variant="ghost"
            size="none"
            onClick={() => setQuantity(quantity + 1)}
            className="p-3 hover:text-primary transition-colors"
            aria-label="Increase quantity"
          >
            <span className="material-symbols-outlined text-lg">add</span>
          </Button>
        </div>

        <Button
          onClick={handleAddToCart}
          disabled={buttonState !== "idle" || !currentVariant}
          className={cn(
            "flex-1 font-medium py-4 transition-all duration-300 relative overflow-hidden group disabled:opacity-70",
            buttonState === "success" ? "bg-green-600 text-white" : ""
          )}
          isLoading={buttonState === "loading"}
        >
          <AnimatePresence mode="wait">
            {buttonState === "idle" && (
              <motion.span
                key="idle"
                initial={{ opacity: 0, y: 5 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -5 }}
                transition={{ duration: 0.2 }}
                className="flex items-center justify-center gap-2"
              >
                Add to Cart
              </motion.span>
            )}
            {buttonState === "success" && (
              <motion.span
                key="success"
                initial={{ opacity: 0, y: 5 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -5 }}
                transition={{ duration: 0.2 }}
                className="flex items-center justify-center gap-2"
              >
                <div className="flex items-center gap-2">
                  <motion.span 
                    initial={{ scale: 0.5 }}
                    animate={{ scale: 1 }}
                    className="material-symbols-outlined text-xl"
                  >
                    check
                  </motion.span>
                  Added
                </div>
              </motion.span>
            )}
          </AnimatePresence>
        </Button>

        <Button
          variant="none"
          size="none"
          onClick={toggleWishlist}
          className={cn(
            "p-4 border transition-colors flex items-center justify-center rounded-sm",
            isFavorite ? "border-red-100 bg-red-50 text-red-600" : "border-outline-variant hover:bg-surface-container text-on-surface"
          )}
          aria-label={isFavorite ? "Remove from wishlist" : "Add to wishlist"}
          icon={
            <motion.span 
              animate={{ scale: isFavorite ? [1, 1.2, 1] : 1 }}
              className={cn(
                "material-symbols-outlined text-xl",
                isFavorite && "fill-current"
              )}
              style={{ fontVariationSettings: `'FILL' ${isFavorite ? 1 : 0}` }}
            >
              favorite
            </motion.span>
          }
        />
      </div>

      <div className="pt-8 border-t border-surface-container space-y-4">
        <div className="flex items-center gap-4">
          <span className="material-symbols-outlined text-on-surface-variant">local_shipping</span>
          <p className="text-sm text-on-surface-variant">Complimentary Carbon-Neutral Shipping</p>
        </div>
      </div>
    </div>
  );
};

"use client";

import React, { useEffect, useState } from "react";
import { productApi, reviewApi } from "@/lib/api";
import { useAuthStore } from "@/store/authStore";
import { motion, AnimatePresence } from "framer-motion";
import { Button } from "../ui/Button";
import { Input } from "../ui/Input";
import { Textarea } from "../ui/Textarea";
import Link from "next/link";
import { cn } from "@/lib/utils";

interface Review {
  id: string;
  user?: {
    name: string;
    avatar?: string;
  };
  rating: number;
  title?: string;
  body: string;
  createdAt: string;
}

interface ProductReviewsProps {
  productId: string;
  avgRating?: number | null;
  reviewCount?: number;
}

export const ProductReviews = ({ productId, avgRating, reviewCount }: ProductReviewsProps) => {
  const [reviews, setReviews] = useState<Review[]>([]);
  const [showForm, setShowForm] = useState(false);
  const [rating, setRating] = useState(5);
  const [title, setTitle] = useState("");
  const [body, setBody] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState("");
  const [hasReviewed, setHasReviewed] = useState(false);

  const { isAuthenticated, user } = useAuthStore();

  useEffect(() => {
    const fetchReviews = async () => {
      try {
        const res = await productApi.getReviews(productId);
        if (res.data.success) {
          const fetchedReviews = res.data.data as Review[];
          setReviews(fetchedReviews);

          // Check if current user has already reviewed
          if (user) {
            const userReview = fetchedReviews.some(r => r.user?.name === user.name);
            setHasReviewed(userReview);
          }
        }
      } catch (err) {
        console.error("Failed to fetch reviews:", err);
      }
    };
    fetchReviews();
  }, [productId, user]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!isAuthenticated) return;

    setIsSubmitting(true);
    setError("");

    try {
      const res = await reviewApi.create({
        productId,
        rating,
        title,
        body
      });

      if (res.data.success) {
        // Add new review to list immediately
        const newReview: Review = {
          ...res.data.data,
          user: { name: user?.name || "Anonymous", avatar: user?.avatar }
        };
        setReviews([newReview, ...reviews]);
        setShowForm(false);
        setHasReviewed(true);
        // Reset form
        setTitle("");
        setBody("");
        setRating(5);
      }
    } catch (err: any) {
      setError(err.response?.data?.message || "Failed to submit review");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <section className="bg-white max-w-[1440px] mx-auto px-8 lg:px-12 py-24 lg:py-32 border-t border-outline-variant/10">
      <div className="grid grid-cols-1 lg:grid-cols-4 gap-16">
        <div className="lg:col-span-1 space-y-8">
          <div className="space-y-4">
            <h2 className="text-3xl font-medium tracking-tight">User Reviews</h2>
            <div className="space-y-2">
              <div className="text-6xl font-bold tracking-tighter">{avgRating != null ? avgRating.toFixed(1) : "—"}</div>
              <div className="flex text-primary">
                {[...Array(5)].map((_, i) => (
                  <span 
                    key={i} 
                    className="material-symbols-outlined text-2xl" 
                    style={{ fontVariationSettings: `'FILL' ${avgRating != null && i < Math.floor(avgRating) ? 1 : 0}` }}
                  >
                    star
                  </span>
                ))}
              </div>
              <p className="text-xs text-on-surface-variant uppercase tracking-[0.2em] font-bold">
                {reviews.length > 0 ? `Based on ${reviews.length} Reviews` : "No reviews yet"}
              </p>
            </div>
          </div>

          <div className="pt-8 border-t border-outline-variant/30">
            {!isAuthenticated ? (
              <div className="space-y-4">
                <p className="text-sm text-on-surface-variant italic">Share your thoughts on this product.</p>
                <Link href={`/login?redirect=/products/${productId}`}>
                  <Button variant="outline" className="w-full text-[10px] uppercase tracking-widest font-bold py-4">
                    Login to Write a Review
                  </Button>
                </Link>
              </div>
            ) : hasReviewed ? (
              <div className="p-4 bg-surface-container-low rounded-sm border border-outline-variant/20">
                <p className="text-sm text-on-surface-variant font-medium text-center">
                  You have already reviewed this product.
                </p>
              </div>
            ) : !showForm ? (
              <Button 
                onClick={() => setShowForm(true)}
                className="w-full py-5 border border-primary text-[10px] uppercase tracking-[0.3em] font-bold hover:bg-primary hover:text-white transition-all duration-300"
                variant="outline"
              >
                Write a Review
              </Button>
            ) : null}
          </div>
        </div>

        <div className="lg:col-span-3 space-y-16">
          <AnimatePresence>
            {showForm && (
              <motion.div
                initial={{ opacity: 0, height: 0 }}
                animate={{ opacity: 1, height: "auto" }}
                exit={{ opacity: 0, height: 0 }}
                className="overflow-hidden"
              >
                <form onSubmit={handleSubmit} className="bg-surface-container-lowest p-8 md:p-12 border border-outline-variant rounded-sm space-y-8">
                  <div className="flex justify-between items-center">
                    <h3 className="text-2xl font-medium tracking-tight">Submit Your Review</h3>
                    <Button variant="ghost" size="icon" onClick={() => setShowForm(false)}>
                      <span className="material-symbols-outlined">close</span>
                    </Button>
                  </div>

                  <div className="space-y-6">
                    <div className="space-y-4">
                      <p className="text-[10px] uppercase tracking-widest font-bold text-on-surface-variant">Rating</p>
                      <div className="flex gap-2">
                        {[1, 2, 3, 4, 5].map((star) => (
                          <Button
                            key={star}
                            type="button"
                            variant="none"
                            size="none"
                            onClick={() => setRating(star)}
                            className="text-primary hover:scale-110 transition-transform cursor-pointer"
                          >
                            <span 
                              className="material-symbols-outlined text-3xl"
                              style={{ fontVariationSettings: `'FILL' ${star <= rating ? 1 : 0}` }}
                            >
                              star
                            </span>
                          </Button>
                        ))}
                      </div>
                    </div>

                    <Input
                      id="title"
                      label="Review Title"
                      value={title}
                      onChange={(e) => setTitle(e.target.value)}
                      placeholder="Sum up your experience"
                      required
                    />

                    <Textarea
                      id="body"
                      label="Your Feedback"
                      rows={5}
                      value={body}
                      onChange={(e) => setBody(e.target.value)}
                      placeholder="What do you like or dislike? How was the fit?"
                      required
                    />
                  </div>

                  {error && (
                    <p className="text-red-600 text-sm font-medium">{error}</p>
                  )}

                  <Button
                    type="submit"
                    isLoading={isSubmitting}
                    disabled={isSubmitting}
                    className="px-12 py-4 bg-primary text-on-primary text-[10px] uppercase tracking-widest font-bold hover:bg-primary/90 transition-all"
                  >
                    Submit Review
                  </Button>
                </form>
              </motion.div>
            )}
          </AnimatePresence>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-x-12 gap-y-16">
            <AnimatePresence mode="popLayout">
              {reviews.length === 0 ? (
                <div className="col-span-full py-12 text-center border-2 border-dashed border-outline-variant/20">
                  <p className="text-on-surface-variant italic">No reviews yet. Be the first to share your experience!</p>
                </div>
              ) : (
                reviews.map((review, idx) => (
                  <motion.div
                    key={review.id}
                    initial={{ opacity: 0, y: 20 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true }}
                    transition={{ duration: 0.5, delay: idx * 0.05 }}
